import sys

def get_int():
    return map(int, sys.stdin.readline().strip().split())

a_x, a_y, b_x, b_y, c_x, c_y = get_int()

def dist(x1, y1, x2, y2):
    return ((x1 - x2) ** 2 + (y1 - y2) ** 2) ** 0.5

if dist(a_x, a_y, b_x, b_y) == dist(b_x, b_y, c_x, c_y):
    print("Yes")
else:
    print("No")
